$lines = $rows -split "`r?`n" | Where-Object { $_.Trim() -ne '' }
$null = $lines[0]
$items = $lines[1..($lines.Count-1)]

foreach ($line in $items) {
  $parts = $line -split '\|', 5
  $path = $parts[0]
  $title = $parts[1]
  $desc = $parts[2]
  $h1 = $parts[3]
  $intro = $parts[4]

  $canonical = 'https://www.lescalculateurs.fr/' + ($path -replace '^src/','' -replace '\\','/' -replace '\.html$','')
  $dir = Split-Path $path -Parent
  if (!(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }

  $html = @"
